DROP TABLE IF EXISTS repair_jobs;
CREATE TABLE repair_jobs (
  slug TEXT PRIMARY KEY, name TEXT, category TEXT, difficulty INTEGER,
  tools TEXT, typical_parts TEXT, likely_sizes TEXT,
  hv_safety INTEGER DEFAULT 0, excluded INTEGER DEFAULT 0, notes TEXT,
  seed_avg_hours REAL, seed_min_hours REAL, seed_max_hours REAL, vehicle_coverage INTEGER);
CREATE INDEX IF NOT EXISTS ix_rj_category ON repair_jobs(category);